                },
                'list_profile': {
                    'model': 'construction.contract',
                    'view_type': 'list',
                    'columns': ['name', 'contract_type', 'state', 'project_id', 'amount_total', 'sign_date'],
                    'column_labels': {
                        'name': '合同名称',
                        'contract_type': '合同类型',
